UPDATE blog_posts
SET title = 'What Is the 25% Rule for Roofing in Florida? (2026 Update)',
    excerpt = 'Florida''s 25% roof rule requires the whole roof to meet current Florida Building Code when more than 25% is repaired in a 12-month period — but the 2022 SB 4-D law exempts roofs permitted on or after March 1, 2009. Here''s how to tell which applies to you.'
WHERE slug = 'what-is-25-percent-rule-roofing-florida';